 1	import {
 2	  Brand,
 3	  Masthead,
 4	  MastheadBrand,
 5	  MastheadContent,
 6	  MastheadMain,
 7	  MastheadToggle,
 8	  PageToggleButton,
 9	  ToggleGroup,
10	  ToggleGroupItem,
11	  Toolbar,
12	  ToolbarContent,
13	  ToolbarItem
14	} from '@patternfly/react-core';
15	import { BarsIcon } from '@patternfly/react-icons';
16	import React from 'react';
17	
18	export const Header: React.FunctionComponent<{
19	  isSidebarOpen: boolean;
20	  onSidebarToggle: () => void;
21	  isDark: boolean;
22	  setDark: (dark: boolean) => void;
23	}> = ({ isSidebarOpen, onSidebarToggle, isDark, setDark }) => {
24	  const onThemeSelect = (isDarkTheme: boolean) => {
25	    setDark(isDarkTheme);
26	    const htmlElement = document.getElementsByTagName('html')[0];
27	    if (htmlElement) {
28	      if (isDarkTheme) {
29	        htmlElement.classList.add('pf-v6-theme-dark');
30	      } else {
31	        htmlElement.classList.remove('pf-v6-theme-dark');
32	      }
33	    }
34	  };
35	
36	  return (
37	    <Masthead>
38	      <MastheadToggle>
39	        <PageToggleButton
40	          variant="plain"
41	          aria-label="Global navigation"
42	          isSidebarOpen={isSidebarOpen}
43	          onSidebarToggle={onSidebarToggle}
44	          id="nav-toggle"
45	        >
46	          <BarsIcon />
47	        </PageToggleButton>
48	      </MastheadToggle>
49	      <MastheadMain>
50	        <MastheadBrand>
51	          <Brand src={'/assets/netobserv.svg'} widths={{ default: '40px' }} alt="NetObserv Logo" />
52	        </MastheadBrand>
53	      </MastheadMain>
54	      <MastheadContent>
55	        <Toolbar id="vertical-toolbar">
56	          <ToolbarContent>
57	            <ToolbarItem className="masthead-link">
58	              <a href="https://netobserv.io" title="Open netobserv.io" target="_blank" rel="noreferrer">
59	                NetObserv
60	              </a>
61	            </ToolbarItem>
62	            <ToolbarItem align={{ default: 'alignRight' }}>
63	              <ToggleGroup>
64	                <ToggleGroupItem text="Light" isSelected={!isDark} onClick={() => onThemeSelect(false)} />
65	                <ToggleGroupItem text="Dark" isSelected={isDark} onClick={() => onThemeSelect(true)} />
66	              </ToggleGroup>
67	            </ToolbarItem>
68	          </ToolbarContent>
69	        </Toolbar>
70	      </MastheadContent>
71	    </Masthead>
72	  );
73	};
74	
75	export default Header;

